from pydantic import BaseModel, Field
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)


class RelevanceGrade(BaseModel):
    relevant: bool = Field(description="True if the passage addresses the query")
    reason: str = Field(description="One sentence justification")


grader_prompt = ChatPromptTemplate.from_messages([
    (
        "system",
        "You are a strict relevance judge. Decide whether the retrieved passage "
        "directly addresses the user's question. Respond True only if it contains "
        "specific facts or reasoning the answer needs.",
    ),
    ("human", "Question: {question}\n\nPassage: {passage}"),
])

grader_llm = grader_prompt | llm.with_structured_output(RelevanceGrade)


def grade_passage(question: str, passage: str) -> RelevanceGrade:
    return grader_llm.invoke({"question": question, "passage": passage})


# Grade a batch of retrieved documents
def grade_documents(question: str, docs: list) -> tuple[list, list]:
    """Returns (relevant_docs, irrelevant_docs)."""
    relevant, irrelevant = [], []
    for doc in docs:
        grade = grade_passage(question, doc.page_content)
        if grade.relevant:
            relevant.append(doc)
        else:
            irrelevant.append(doc)
    return relevant, irrelevant

from langchain_community.tools.tavily_search import TavilySearchResults
from langchain_core.documents import Document

web_search = TavilySearchResults(max_results=4)


def rewrite_query_for_web(question: str, llm) -> str:
    """Make the query more search-engine friendly."""
    prompt = (
        f"Rewrite the following question into a concise web search query "
        f"(no filler words, no question marks):\n{question}"
    )
    return llm.invoke(prompt).content.strip()


def web_search_docs(question: str, llm) -> list[Document]:
    search_query = rewrite_query_for_web(question, llm)
    results = web_search.invoke(search_query)
    return [
        Document(
            page_content=r["content"],
            metadata={"source": r["url"], "origin": "web"},
        )
        for r in results
    ]

from typing import TypedDict, Literal
from langchain_core.documents import Document
from langgraph.graph import StateGraph, END

class CRAGState(TypedDict):
    question: str
    documents: list[Document]
    grade: Literal["relevant", "irrelevant", "mixed"]
    answer: str


def retrieve_node(state: CRAGState) -> CRAGState:
    docs = retriever.invoke(state["question"])
    return {**state, "documents": docs}


def grade_node(state: CRAGState) -> CRAGState:
    relevant, irrelevant = grade_documents(state["question"], state["documents"])
    if len(relevant) == len(state["documents"]):
        grade = "relevant"
    elif not relevant:
        grade = "irrelevant"
    else:
        grade = "mixed"
    return {**state, "documents": relevant or state["documents"], "grade": grade}


def web_search_node(state: CRAGState) -> CRAGState:
    web_docs = web_search_docs(state["question"], llm)
    if state["grade"] == "mixed":
        combined = state["documents"] + web_docs
    else:
        combined = web_docs
    return {**state, "documents": combined}


def generate_node(state: CRAGState) -> CRAGState:
    context = "\n\n".join(d.page_content for d in state["documents"])
    answer = generate_chain.invoke({"context": context, "question": state["question"]})
    return {**state, "answer": answer}


def route_after_grade(state: CRAGState) -> str:
    return "web_search" if state["grade"] in ("irrelevant", "mixed") else "generate"


graph = StateGraph(CRAGState)
graph.add_node("retrieve", retrieve_node)
graph.add_node("grade", grade_node)
graph.add_node("web_search", web_search_node)
graph.add_node("generate", generate_node)

graph.set_entry_point("retrieve")
graph.add_edge("retrieve", "grade")
graph.add_conditional_edges("grade", route_after_grade, {
    "web_search": "web_search",
    "generate": "generate",
})
graph.add_edge("web_search", "generate")
graph.add_edge("generate", END)

crag_app = graph.compile()

result = crag_app.invoke({"question": "What are the CRAG routing strategies?"})
print(result["answer"])
